class Solution {
    public int[] findValidSequence(String word1, String word2) {
        int[] result = new int[word2.length()];
        int j = 0;
        int k = 0;
        int minDiff = Integer.MAX_VALUE;

        for (int i = 0; i < word1.length(); i++) {
            if (word1.charAt(i) != word2.charAt(j)) {
                minDiff = Math.min(minDiff, Math.abs(word1.charAt(i) - word2.charAt(j));
                result[k++] = i;
            }
            j++;
        }

        for (int i = 0; i < word2.length(); i++) {
            if (word1.charAt(result[k-1]) != word2.charAt(i)) {
                minDiff = Math.min(minDiff, Math.abs(word1.charAt(result[k-1]) - word2.charAt(i));
                result[k++] = i;
            }
        }

        return result;
    }
}
